import{c as a,Q as n,j as t,m as o}from"./chunks/framework.CBiVa4O3.js";const g=JSON.parse('{"title":"CAP 与 PACELC 与 BASE","description":"","frontmatter":{},"headers":[],"relativePath":"../distributedLearning/04-CAP与PACELC与BASE.md","filePath":"../distributedLearning/04-CAP与PACELC与BASE.md","lastUpdated":1778496697000}'),e={name:"../distributedLearning/04-CAP与PACELC与BASE.md"};function l(p,s,i,r,d,c){return n(),t("div",null,[...s[0]||(s[0]=[o(`<h1 id="cap-与-pacelc-与-base" tabindex="-1">CAP 与 PACELC 与 BASE <a class="header-anchor" href="#cap-与-pacelc-与-base" aria-label="Permalink to &quot;CAP 与 PACELC 与 BASE&quot;">​</a></h1><p>CAP 是分布式系统课的第一道开胃菜,也是被讲坏得最厉害的一道。<strong>面试时背 &quot;三选二&quot; 能拿三分,真正写系统时背 &quot;三选二&quot; 能让你出大事故</strong>。这一篇不重复 systemDesign 那篇的工程口径,而是补三件事:Brewer 2000 PODC 演讲到底说了什么、Gilbert-Lynch 2002 论文怎么把它形式化(以及证明的边界在哪)、为什么 2012 年之后业界用 PACELC 取代 CAP、BASE 怎么在工程上真正落地。<strong>看完这一篇,你应该能在白板上对架构师讲清楚&quot;我们这个系统在 PACELC 上的位置在哪、为什么这样选&quot;</strong>——而不是&quot;我们是 CP 公司&quot;这种没意义的标签。</p><blockquote><p>一句话先记住:<strong>CAP 是一句关于&quot;网络分区下的不变量&quot;的断言,不是分布式系统的世界观</strong>。<strong>P 不是给你选的</strong>——它是异步网络的物理事实,<strong>真正的取舍发生在两个时刻</strong>:分区时(C vs A)和正常运行时(C vs L)。PACELC 把后半句补上,BASE 把工程妥协具象化。<strong>&quot;CA 系统&quot; 是伪概念,&quot;AP / CP 标签&quot; 是粗暴标记</strong>——真实系统是&quot;按数据 / 按操作 / 按时刻&quot;精细化选择的。</p></blockquote><hr><h2 id="一、cap-的原始版本到底说了什么" tabindex="-1">一、CAP 的原始版本到底说了什么 <a class="header-anchor" href="#一、cap-的原始版本到底说了什么" aria-label="Permalink to &quot;一、CAP 的原始版本到底说了什么&quot;">​</a></h2><p>2000 年 7 月,Eric Brewer 在 PODC(Principles of Distributed Computing)做了一个 keynote,题目叫 <em>Towards Robust Distributed Systems</em>。<strong>他没有写论文,只放了几页 slides</strong>——CAP 这个词第一次出现就是在这个 keynote 里,而且只是一个口头观察(conjecture),不是定理。</p><p>Brewer 当年讲的原文大意是:</p><blockquote><p>在共享数据的分布式系统里,<strong>一致性(Consistency)、可用性(Availability)、分区容忍性(Partition tolerance)三个属性,你最多只能同时拿到两个</strong>。</p></blockquote><p>注意三个细节:</p><ol><li><strong>这是&quot;猜想&quot;,不是&quot;定理&quot;</strong>——Brewer 自己说这是经验观察,不是数学结果</li><li><strong>没有给出三个属性的精确定义</strong>——Consistency 到底多强、Availability 到底多高、Partition 到底是什么样的分区,全部模糊</li><li><strong>没有数学证明</strong>——只是从多年做 Inktomi 搜索引擎、做 BASE 系统的经验里总结出来的直觉</li></ol><p>所以最初的 CAP 是一句&quot;工程师的格言&quot;,<strong>不是教科书拿来发挥成&quot;三选二定理&quot;的那个东西</strong>。把它讲成&quot;三选二的铁律&quot;是后人加戏。</p><hr><h2 id="二、gilbert-lynch-2002-把-cap-形式化-以及边界在哪" tabindex="-1">二、Gilbert-Lynch 2002:把 CAP 形式化(以及边界在哪) <a class="header-anchor" href="#二、gilbert-lynch-2002-把-cap-形式化-以及边界在哪" aria-label="Permalink to &quot;二、Gilbert-Lynch 2002:把 CAP 形式化(以及边界在哪)&quot;">​</a></h2><p>两年后,MIT 的 Seth Gilbert 和 Nancy Lynch 写了一篇 <em>Brewer&#39;s Conjecture and the Feasibility of Consistent, Available, Partition-Tolerant Web Services</em>,<strong>把 CAP 在一个特定模型下证明了</strong>。这才是后来教科书里那个&quot;CAP 定理&quot;。</p><p>但这个证明的前提非常具体,<strong>不读论文你不知道它在证什么</strong>:</p><table tabindex="0"><thead><tr><th>元素</th><th>论文里的具体定义</th></tr></thead><tbody><tr><td><strong>Consistency</strong></td><td><strong>线性一致性(linearizability)</strong>——读返回最近一次写,所有节点视图等价于单机</td></tr><tr><td><strong>Availability</strong></td><td><strong>每个非故障节点收到的请求,必须最终返回非错响应</strong>——不限时长,但要求有响应</td></tr><tr><td><strong>Partition tolerance</strong></td><td><strong>网络可以丢任意多条消息</strong>(模型化为消息可任意延迟或丢失)</td></tr><tr><td><strong>环境</strong></td><td><strong>异步模型</strong>——节点之间没有共享时钟,消息延迟无上限</td></tr></tbody></table><p><strong>核心证明思路</strong>(白板上能讲清楚):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>假设系统在分区时既能保 C 又能保 A。</span></span>
<span class="line"><span>设两个节点 N1、N2,初始数据相同(都是 v0)。</span></span>
<span class="line"><span>网络分区,N1 和 N2 互相收不到消息。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  客户端 A 写 N1:v0 → v1   (N1 必须接受,A 要保)</span></span>
<span class="line"><span>  客户端 B 读 N2          (N2 必须返回,A 要保)</span></span>
<span class="line"><span>                          (N2 必须返回 v1,C 要保)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>但 N2 收不到 N1 的消息,根本不知道 v1 存在。</span></span>
<span class="line"><span>矛盾。证毕。</span></span></code></pre></div><p>短短几行就能把这条结论推出来。但<strong>这个证明的&quot;边界&quot;经常被忽略</strong>:</p><ol><li><strong>只在异步模型下成立</strong>。论文也证了&quot;部分同步模型(节点知道一个延迟上限)下,可以在分区结束后恢复 C+A&quot;——也就是说现实工程中&quot;分区恢复后回到强一致&quot; 是允许的,<strong>CAP 不否认这个</strong></li><li><strong>Consistency 限定为线性一致性</strong>。<strong>因果一致、最终一致这些较弱的模型,不在 CAP 的禁令里</strong>——这是为什么 CRDT / Bolt-on Causal 那一派能&quot;绕过 CAP&quot;</li><li><strong>Availability 是&quot;总有响应&quot;,不是&quot;低延迟响应&quot;</strong>——CAP 不管你响应要等多久,<strong>这是 PACELC 后来补的洞</strong></li></ol><blockquote><p><strong>CAP 是一个具体模型下的具体不可能结果</strong>,它不是一个能拿来贴在任何系统上的标签。把它误读成&quot;普遍真理&quot;是教科书的锅,不是 Gilbert-Lynch 的锅。</p></blockquote><hr><h2 id="三、为什么-ca-系统-是个伪概念" tabindex="-1">三、为什么 &quot;CA 系统&quot; 是个伪概念 <a class="header-anchor" href="#三、为什么-ca-系统-是个伪概念" aria-label="Permalink to &quot;三、为什么 &quot;CA 系统&quot; 是个伪概念&quot;">​</a></h2><p>很多人讲 CAP 时画一个三角形:CA / CP / AP 三个角,<strong>告诉你 MySQL 是 CA、ZK 是 CP、Cassandra 是 AP</strong>。这个三角形是错的。</p><p><strong>P 不是选项</strong>。在任何跨网络的分布式系统里,<strong>网络分区是物理事实</strong>——你不能&quot;选择不容忍分区&quot;,分区会自己来:</p><ul><li>机房交换机重启 30 秒</li><li>跨城光纤被挖掉</li><li>防火墙规则配错</li><li>节点 GC stop-the-world 看起来像分区</li><li>节点慢得跟分区一样(灰故障)</li></ul><p>如果你&quot;不容忍分区&quot;,那分区发生时你的系统直接挂——<strong>这等于你&quot;用不可用来换取假装一致性&quot;,但实际上一致性也保不住</strong>(因为节点根本不响应,你怎么知道它一致?)。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>理论上的 CAP 三角(错误教学版):</span></span>
<span class="line"><span>                    C</span></span>
<span class="line"><span>                   ╱ ╲</span></span>
<span class="line"><span>              CA ╱   ╲ CP</span></span>
<span class="line"><span>                ╱     ╲</span></span>
<span class="line"><span>              ╱        ╲</span></span>
<span class="line"><span>            A ───────── P</span></span>
<span class="line"><span>                  AP</span></span>
<span class="line"><span></span></span>
<span class="line"><span>实际上的样子(正确版):</span></span>
<span class="line"><span>              C ───────── A</span></span>
<span class="line"><span>                  ╲     ╱</span></span>
<span class="line"><span>                   ╲   ╱</span></span>
<span class="line"><span>                    ╲ ╱</span></span>
<span class="line"><span>                  分区时</span></span>
<span class="line"><span>                  二选一</span></span>
<span class="line"><span>              </span></span>
<span class="line"><span>              (P 永远在那里,不在你的选项里)</span></span></code></pre></div><h3 id="_3-1-mysql-是-ca-的常见误读" tabindex="-1">3.1 &quot;MySQL 是 CA&quot; 的常见误读 <a class="header-anchor" href="#_3-1-mysql-是-ca-的常见误读" aria-label="Permalink to &quot;3.1 &quot;MySQL 是 CA&quot; 的常见误读&quot;">​</a></h3><p>有人说 MySQL 单机是 CA、不考虑分区,所以是 CA。<strong>严格说也对——但 MySQL 单机不是分布式系统,套 CAP 没意义</strong>。</p><p>一旦你说&quot;MySQL 主从&quot;,它就是分布式系统了:</p><ul><li>主从异步复制 + 主挂自动切从:<strong>分区时主从可能脑裂(都以为自己是主)→ 不是 C,是 AP</strong></li><li>主从异步复制 + 主挂不切:<strong>分区时主不可用 → 不是 A,是 CP(还是个弱化的 CP,因为复制本来就是弱一致)</strong></li><li>半同步 + 主挂自动切:<strong>分区时如果多数从断连,主写不下去 → 偏 CP</strong></li></ul><p><strong>没有&quot;CA 数据库&quot;</strong>。任何一个真实分布式系统都在 CP / AP 的连续谱上。</p><hr><h2 id="四、pacelc-把-cap-漏掉的那一半补回来" tabindex="-1">四、PACELC:把 CAP 漏掉的那一半补回来 <a class="header-anchor" href="#四、pacelc-把-cap-漏掉的那一半补回来" aria-label="Permalink to &quot;四、PACELC:把 CAP 漏掉的那一半补回来&quot;">​</a></h2><p>CAP 只回答了&quot;分区时怎么办&quot;。但真实系统<strong>99.9% 的时间都没分区</strong>——这 99.9% 的时间里,系统在做什么取舍?<strong>CAP 不回答</strong>。</p><p>2010 年,耶鲁大学的 Daniel Abadi 提出 <strong>PACELC</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PACELC 念法:Pack-Elk</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if (P) then choose between A and C</span></span>
<span class="line"><span>else      choose between L and C</span></span>
<span class="line"><span></span></span>
<span class="line"><span>P  = Partition</span></span>
<span class="line"><span>A  = Availability</span></span>
<span class="line"><span>C  = Consistency</span></span>
<span class="line"><span>E  = Else (no partition)</span></span>
<span class="line"><span>L  = Latency</span></span></code></pre></div><p>中文表述:<strong>分区时(P),选 A 还是 C;否则(E),选 L 还是 C</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        ┌──────────────────────────────────┐</span></span>
<span class="line"><span>        │       PACELC 决策树              │</span></span>
<span class="line"><span>        │                                  │</span></span>
<span class="line"><span>        │   网络分区?                      │</span></span>
<span class="line"><span>        │     │                            │</span></span>
<span class="line"><span>        │     ├─ 是 → PA  or  PC           │</span></span>
<span class="line"><span>        │     │                            │</span></span>
<span class="line"><span>        │     └─ 否 → EL  or  EC           │</span></span>
<span class="line"><span>        │                                  │</span></span>
<span class="line"><span>        └──────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>四个组合,贴到真实系统:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  PA / EL : 分区时选 A,平时选低延迟(放弃强一致)</span></span>
<span class="line"><span>            → DynamoDB, Cassandra, Riak</span></span>
<span class="line"><span>            </span></span>
<span class="line"><span>  PC / EC : 分区时选 C,平时也选 C(接受高延迟)</span></span>
<span class="line"><span>            → BigTable, HBase, Spanner, MongoDB(majority)</span></span>
<span class="line"><span>            </span></span>
<span class="line"><span>  PA / EC : 分区时选 A,平时选 C</span></span>
<span class="line"><span>            → 比较罕见,理论上存在</span></span>
<span class="line"><span>            </span></span>
<span class="line"><span>  PC / EL : 分区时选 C,平时选 L</span></span>
<span class="line"><span>            → MySQL 异步复制(分区时主不可用,平时低延迟但弱一致)</span></span></code></pre></div><h3 id="_4-1-用-pacelc-重新标主流系统" tabindex="-1">4.1 用 PACELC 重新标主流系统 <a class="header-anchor" href="#_4-1-用-pacelc-重新标主流系统" aria-label="Permalink to &quot;4.1 用 PACELC 重新标主流系统&quot;">​</a></h3><table tabindex="0"><thead><tr><th>系统</th><th>PACELC</th><th>解读</th></tr></thead><tbody><tr><td><strong>DynamoDB</strong>(默认最终一致读)</td><td>PA/EL</td><td>分区时继续服务,正常时低延迟优先</td></tr><tr><td><strong>DynamoDB</strong>(强一致读模式)</td><td>PC/EC</td><td>强一致读必须等多数派,延迟高</td></tr><tr><td><strong>Cassandra</strong>(默认 ONE)</td><td>PA/EL</td><td>任意一个副本响应就返回,<strong>最快但可能读到旧数据</strong></td></tr><tr><td><strong>Cassandra</strong>(QUORUM 写 + QUORUM 读)</td><td>PC/EC</td><td>多数派确认,<strong>慢但强一致(注意 R+W&gt;N 才严格成立)</strong></td></tr><tr><td><strong>Spanner</strong></td><td>PC/EC</td><td>TrueTime + Paxos,<strong>任何时候都强一致</strong>,代价是 TrueTime 等待</td></tr><tr><td><strong>MongoDB</strong>(WriteConcern=majority)</td><td>PC/EC</td><td>多数派确认,选主分区时少数派不可写</td></tr><tr><td><strong>BigTable / HBase</strong></td><td>PC/EC</td><td>单 Tablet 单主,分区时少数派不可用</td></tr><tr><td><strong>ZooKeeper / etcd</strong></td><td>PC/EC</td><td>共识协议要求多数派,分区时少数派 read 也可能拒(zk linearizable read)</td></tr><tr><td><strong>MySQL 异步主从</strong></td><td>PA/EL</td><td>主挂可丢已确认事务,平时低延迟</td></tr><tr><td><strong>Redis 主从</strong></td><td>PA/EL</td><td>默认异步复制,主挂可能丢数据</td></tr><tr><td><strong>Kafka</strong>(acks=all + min.insync.replicas=majority)</td><td>PC/EC</td><td>少数派 broker 拒写</td></tr></tbody></table><blockquote><p><strong>PACELC 比 CAP 实用 10 倍</strong>——它把&quot;平时的延迟代价&quot;也放上桌面。<strong>强一致从来不是免费的:即使没分区,跨地域的强一致也意味着一次写要跨太平洋一个 RTT</strong>——150ms 起步。<strong>这就是为什么 Spanner 装原子钟也无法把延迟降到 0</strong>。</p></blockquote><hr><h2 id="五、base-cap-工程化的现实派" tabindex="-1">五、BASE:CAP 工程化的现实派 <a class="header-anchor" href="#五、base-cap-工程化的现实派" aria-label="Permalink to &quot;五、BASE:CAP 工程化的现实派&quot;">​</a></h2><p>CAP 是学术派,BASE 是工程派。<strong>BASE 来自 eBay 工程师 Dan Pritchett 在 2008 年 ACM Queue 上写的一篇文章</strong>,把当年互联网行业绕开 ACID 的实战经验总结成了一句口号:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>B - Basically Available  基本可用</span></span>
<span class="line"><span>A - Soft state           软状态</span></span>
<span class="line"><span>E - Eventual consistency 最终一致</span></span></code></pre></div><p>systemDesign 那篇已经讲过 BASE 怎么对应到电商业务,这里补&quot;BASE 工程化怎么真的落地&quot;——三件事缺一不可。</p><h3 id="_5-1-basically-available-降级而不是全挂" tabindex="-1">5.1 Basically Available:降级而不是全挂 <a class="header-anchor" href="#_5-1-basically-available-降级而不是全挂" aria-label="Permalink to &quot;5.1 Basically Available:降级而不是全挂&quot;">​</a></h3><p>&quot;基本可用&quot; 不是&quot;挂着但凑合用&quot;,而是<strong>主动设计降级路径</strong>。要在系统里写代码:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> get_recommendations</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(user_id):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    try</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> recommendation_service.get(user_id, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">timeout</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">50ms</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    except</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (Timeout, ServiceDown):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fallback_popular_items()  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 兜底</span></span></code></pre></div><ul><li><strong>熔断器</strong>(Hystrix / Sentinel / Resilience4j):超过阈值的失败率就直接走兜底,不再打下游</li><li><strong>舱壁隔离</strong>(Bulkhead):线程池 / 信号量隔离,避免一个慢服务拖垮全栈</li><li><strong>业务降级开关</strong>:大促前关闭推荐、评价、积分写入</li></ul><blockquote><p><strong>&quot;全有或全无&quot; 是错误的可用性思维</strong>。真实系统永远在做&quot;哪些功能可以临时降级&quot;的取舍——<strong>做不到这一点的系统,SLA 永远到不了 99.95%</strong>。</p></blockquote><h3 id="_5-2-soft-state-接受中间态-但要可观测" tabindex="-1">5.2 Soft State:接受中间态,但要可观测 <a class="header-anchor" href="#_5-2-soft-state-接受中间态-但要可观测" aria-label="Permalink to &quot;5.2 Soft State:接受中间态,但要可观测&quot;">​</a></h3><p>&quot;软状态&quot; 是承认 <strong>数据在副本间、服务间、缓存与 DB 之间的不一致是常态</strong>——但<strong>不能不可见</strong>。工程上要做的是:</p><ul><li><strong>每个不一致的状态有 TTL</strong> —— 缓存有过期、订单 pending 有超时关单</li><li><strong>每个跨服务状态变更有事件 / 消息</strong>(订单状态变更触发库存、积分、消息推送)</li><li><strong>有&quot;对账&quot;机制</strong>——离线 Job 每天检查关键数据(订单 vs 支付 vs 库存)</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>软状态的危险:不一致 + 不可观测 + 不收敛 = 灾难</span></span>
<span class="line"><span></span></span>
<span class="line"><span>正确做法:</span></span>
<span class="line"><span>  数据有 TTL → 自动收敛(过期重读)</span></span>
<span class="line"><span>  状态有事件 → 触发下游(消息驱动)</span></span>
<span class="line"><span>  系统有对账 → 兜底修复(每天一次)</span></span></code></pre></div><h3 id="_5-3-eventual-consistency-最终一致-但要给-最终-加一个数" tabindex="-1">5.3 Eventual Consistency:最终一致,但要给&quot;最终&quot;加一个数 <a class="header-anchor" href="#_5-3-eventual-consistency-最终一致-但要给-最终-加一个数" aria-label="Permalink to &quot;5.3 Eventual Consistency:最终一致,但要给&quot;最终&quot;加一个数&quot;">​</a></h3><p>最容易踩的坑——&quot;最终一致&quot; 听起来像&quot;反正会一致&quot;,<strong>但你不能不知道是多久</strong>。</p><p>每个 eventual consistency 的链路都要回答两个问题:</p><ol><li><strong>收敛时间窗口是多少?</strong> 100ms / 1s / 10s?决定上游能否同步读</li><li><strong>不收敛时怎么知道?</strong> 监控、对账、人工告警</li></ol><p>工程上要做:</p><ul><li>测量复制延迟(MySQL <code>Seconds_Behind_Master</code>、Kafka consumer lag、Redis 主从延迟)</li><li>设置告警阈值(主从延迟 &gt; 5s 报警)</li><li>对账兜底(每日 / 每小时定期对账)</li><li>不允许&quot;读自己写&quot; 的链路依赖最终一致(用户改完头像必须立刻看到,<strong>不能等异步复制</strong>)</li></ul><blockquote><p><strong>互联网公司的 99% 都跑在 BASE 上</strong>。强一致(ACID + 2PC)是金融业的根基,但电商、社交、内容、广告、推荐都用 BASE 撑住了 100 倍以上的流量。<strong>学会 BASE 思维 = 学会做互联网架构。</strong></p></blockquote><hr><h2 id="六、反-cap-误读手册-这些坑你迟早会踩" tabindex="-1">六、反 CAP 误读手册:这些坑你迟早会踩 <a class="header-anchor" href="#六、反-cap-误读手册-这些坑你迟早会踩" aria-label="Permalink to &quot;六、反 CAP 误读手册:这些坑你迟早会踩&quot;">​</a></h2><h3 id="_6-1-三选二-是错的" tabindex="-1">6.1 &quot;三选二&quot; 是错的 <a class="header-anchor" href="#_6-1-三选二-是错的" aria-label="Permalink to &quot;6.1 &quot;三选二&quot; 是错的&quot;">​</a></h3><p>正确说法是 <strong>&quot;分区时二选一&quot;</strong>。平时(没分区)CAP 不限制你,你 C / A 可以都拿。</p><h3 id="_6-2-我们是-cp-ap-公司-是错的" tabindex="-1">6.2 &quot;我们是 CP / AP 公司&quot; 是错的 <a class="header-anchor" href="#_6-2-我们是-cp-ap-公司-是错的" aria-label="Permalink to &quot;6.2 &quot;我们是 CP / AP 公司&quot; 是错的&quot;">​</a></h3><p>CAP 不是公司标签。<strong>同一家公司、同一个系统、同一份代码,不同接口可以选不同侧</strong>:</p><table tabindex="0"><thead><tr><th>接口</th><th>倾向</th><th>理由</th></tr></thead><tbody><tr><td><code>POST /transfer</code>(转账)</td><td>CP</td><td>不能多扣</td></tr><tr><td><code>GET /products</code>(商品列表)</td><td>AP</td><td>看到旧数据没事,系统挂了流失大</td></tr><tr><td><code>POST /like</code>(点赞)</td><td>AP(异步)</td><td>几秒不一致用户感知不到</td></tr><tr><td><code>POST /login</code>(登录)</td><td>CP(对黑名单)</td><td>黑名单同步要快</td></tr></tbody></table><h3 id="_6-3-acid-cp、base-ap-是过简" tabindex="-1">6.3 &quot;ACID = CP、BASE = AP&quot; 是过简 <a class="header-anchor" href="#_6-3-acid-cp、base-ap-是过简" aria-label="Permalink to &quot;6.3 &quot;ACID = CP、BASE = AP&quot; 是过简&quot;">​</a></h3><p>ACID 描述的是事务的本地属性(原子、一致、隔离、持久),<strong>和 CAP 不是同一个 axis</strong>:</p><ul><li>单机 ACID:不涉及 CAP</li><li>分布式 ACID(2PC):<strong>协调者挂了会卡死,这是另一种&quot;不可用&quot;</strong>,不能简单说是 CP</li><li>BASE 不是 &quot;AP&quot;,BASE 是&quot;工程取舍&quot;,<strong>它可以叠在 AP 上(主流),也可以叠在 CP 上(强一致系统也需要降级 / 兜底)</strong></li></ul><h3 id="_6-4-nosql-ap-是错的" tabindex="-1">6.4 &quot;NoSQL = AP&quot; 是错的 <a class="header-anchor" href="#_6-4-nosql-ap-是错的" aria-label="Permalink to &quot;6.4 &quot;NoSQL = AP&quot; 是错的&quot;">​</a></h3><table tabindex="0"><thead><tr><th>数据库</th><th>默认倾向</th></tr></thead><tbody><tr><td>MongoDB(WriteConcern=majority)</td><td>CP</td></tr><tr><td>HBase</td><td>CP</td></tr><tr><td>Cassandra(默认)</td><td>AP</td></tr><tr><td>Cassandra(QUORUM)</td><td>CP</td></tr><tr><td>DynamoDB(默认)</td><td>AP</td></tr><tr><td>DynamoDB(强一致读)</td><td>CP</td></tr></tbody></table><p><strong>SQL / NoSQL 的标签和 CAP 没有必然联系</strong>。SQL 数据库(CockroachDB / Spanner / TiDB)是分布式 CP,NoSQL 也分 CP / AP。</p><h3 id="_6-5-强一致-慢-是过简" tabindex="-1">6.5 &quot;强一致 = 慢&quot; 是过简 <a class="header-anchor" href="#_6-5-强一致-慢-是过简" aria-label="Permalink to &quot;6.5 &quot;强一致 = 慢&quot; 是过简&quot;">​</a></h3><p>强一致一定有共识开销,但<strong>不一定慢得不能用</strong>:</p><ul><li>同机房 Raft:写 1-3ms</li><li>同地域 Raft:写 5-10ms</li><li>跨地域 Raft:写 50-100ms(注定的物理延迟)</li><li>Spanner 跨洲:写 100-200ms</li></ul><p><strong>慢不慢取决于&quot;你能不能接受这个延迟&quot;,而不是&quot;强一致必然不能用&quot;</strong>。</p><h3 id="_6-6-分区很少发生-是错的" tabindex="-1">6.6 &quot;分区很少发生&quot; 是错的 <a class="header-anchor" href="#_6-6-分区很少发生-是错的" aria-label="Permalink to &quot;6.6 &quot;分区很少发生&quot; 是错的&quot;">​</a></h3><p>Google SRE 在 <em>The Tail at Scale</em> 里讲过:<strong>生产环境每月都会有显著的分区事件</strong>——交换机故障、配置错误、防火墙规则、跨机房抖动、灰故障(节点慢得跟分区一样)。<strong>没设计分区容错的系统迟早出大事</strong>。</p><hr><h2 id="七、brewer-2012-cap-十二年后的反思" tabindex="-1">七、Brewer 2012:CAP 十二年后的反思 <a class="header-anchor" href="#七、brewer-2012-cap-十二年后的反思" aria-label="Permalink to &quot;七、Brewer 2012:CAP 十二年后的反思&quot;">​</a></h2><p>2012 年,Brewer 在 IEEE Computer 写了一篇 <em>CAP Twelve Years Later: How the &quot;Rules&quot; Have Changed</em>——<strong>自我修正了当年那个 keynote 留下的误读</strong>。三个关键观点:</p><h3 id="_7-1-三选二-是误导" tabindex="-1">7.1 &quot;三选二&quot; 是误导 <a class="header-anchor" href="#_7-1-三选二-是误导" aria-label="Permalink to &quot;7.1 &quot;三选二&quot; 是误导&quot;">​</a></h3><p>Brewer 自己承认:<strong>当年那个口号过于简化</strong>。真实系统在分区时也不是&quot;完全放弃 C 或 A&quot;,而是<strong>部分放弃</strong>:</p><ul><li>分区时:对<strong>关键操作</strong>(转账)选 C(拒绝写),对<strong>非关键操作</strong>(浏览)继续选 A</li><li>分区结束后:<strong>主动修复期</strong>——通过对账、合并、版本协调把分区期间的不一致补回来</li></ul><h3 id="_7-2-高可用-cp-不等于破-cap" tabindex="-1">7.2 高可用 CP 不等于破 CAP <a class="header-anchor" href="#_7-2-高可用-cp-不等于破-cap" aria-label="Permalink to &quot;7.2 高可用 CP 不等于破 CAP&quot;">​</a></h3><p>Spanner 是 CP 系统(PC/EC),但 Google 公布的可用性是 <strong>5 个 9 (99.999%)</strong>——一年宕机不到 5 分钟。怎么做到的?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高可用 ≠ 不需要 P</span></span>
<span class="line"><span>高可用 = 通过工程手段把&quot;分区导致的不可用时间&quot;压到极短</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工程武器:</span></span>
<span class="line"><span>  1. 多副本(5 副本 Paxos)→ 单点分区不影响多数派</span></span>
<span class="line"><span>  2. 多机房 + 多区域 → 整个机房分区也能多数派活</span></span>
<span class="line"><span>  3. 快速选主(秒级) → 分区导致 Leader 切换时间短</span></span>
<span class="line"><span>  4. 客户端重试 → 短暂不可用对用户不可见</span></span>
<span class="line"><span>  5. 跨地域 Quorum → 1 个地域分区不影响全局可用</span></span></code></pre></div><blockquote><p><strong>&quot;CP 系统不可用率高&quot; 是过时的认知</strong>。<strong>用足够多副本 + 足够多地域,CP 系统的可用率可以比 AP 系统还高</strong>——因为 AP 系统的&quot;假可用&quot;(返回脏数据导致业务出错)不算真可用。</p></blockquote><h3 id="_7-3-分区不是一个开关-是一个连续谱" tabindex="-1">7.3 分区不是一个开关,是一个连续谱 <a class="header-anchor" href="#_7-3-分区不是一个开关-是一个连续谱" aria-label="Permalink to &quot;7.3 分区不是一个开关,是一个连续谱&quot;">​</a></h3><p>真实的&quot;分区&quot; 不是网络断了 / 没断这么二元,<strong>而是延迟 / 丢包率连续变化</strong>:</p><ul><li>完全正常:延迟 1ms,丢包 0</li><li>轻度抖动:延迟 100ms,丢包 0.1%</li><li>明显抖动:延迟 1s,丢包 5%</li><li>灰故障:90% 正常 + 10% 超时</li><li>半分区:A 能到 B,B 不能到 A</li><li>完全分区:互不可达</li></ul><p><strong>CAP 把分区当成离散事件,但生产环境最多的是&quot;灰分区&quot;</strong>——比硬分区更难处理。<strong>这是为什么 Jepsen 测试要专门测网络抖动、丢包、半分区,而不只是测断网</strong>。</p><hr><h2 id="八、把-cap-pacelc-base-串成一张地图" tabindex="-1">八、把 CAP / PACELC / BASE 串成一张地图 <a class="header-anchor" href="#八、把-cap-pacelc-base-串成一张地图" aria-label="Permalink to &quot;八、把 CAP / PACELC / BASE 串成一张地图&quot;">​</a></h2><p>如果你只能记一张图,记这张:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>            ┌──────────────────────────────────────┐</span></span>
<span class="line"><span>            │   理论:CAP(2000) / Gilbert-Lynch(2002) │</span></span>
<span class="line"><span>            │   断言:分区时,C 和 A 不能兼得         │</span></span>
<span class="line"><span>            │   边界:线性一致 + 总有响应 + 异步模型  │</span></span>
<span class="line"><span>            └──────────────────────────────────────┘</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            ▼</span></span>
<span class="line"><span>            ┌──────────────────────────────────────┐</span></span>
<span class="line"><span>            │   细化:PACELC(2010, Daniel Abadi)    │</span></span>
<span class="line"><span>            │   补充:平时(无分区)C 和 L 也不兼得    │</span></span>
<span class="line"><span>            │   工程价值:延迟也要算进取舍           │</span></span>
<span class="line"><span>            └──────────────────────────────────────┘</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            ▼</span></span>
<span class="line"><span>            ┌──────────────────────────────────────┐</span></span>
<span class="line"><span>            │   工程:BASE(2008, eBay)              │</span></span>
<span class="line"><span>            │   落地:基本可用 / 软状态 / 最终一致    │</span></span>
<span class="line"><span>            │   配套:降级 / 熔断 / 对账 / 监控       │</span></span>
<span class="line"><span>            └──────────────────────────────────────┘</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            ▼</span></span>
<span class="line"><span>            ┌──────────────────────────────────────┐</span></span>
<span class="line"><span>            │   现代视角:CAP 十二年后(2012, Brewer) │</span></span>
<span class="line"><span>            │   修正:不是离散三选二,是连续谱       │</span></span>
<span class="line"><span>            │   实践:高可用 CP 不破 CAP             │</span></span>
<span class="line"><span>            └──────────────────────────────────────┘</span></span></code></pre></div><h3 id="_8-1-一张总表-理论-→-工程" tabindex="-1">8.1 一张总表:理论 → 工程 <a class="header-anchor" href="#_8-1-一张总表-理论-→-工程" aria-label="Permalink to &quot;8.1 一张总表:理论 → 工程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>CAP</th><th>PACELC</th><th>BASE</th></tr></thead><tbody><tr><td>年代</td><td>2000</td><td>2010</td><td>2008</td></tr><tr><td>提出者</td><td>Brewer</td><td>Daniel Abadi</td><td>eBay(Dan Pritchett)</td></tr><tr><td>适用时刻</td><td>分区时</td><td>分区时 + 平时</td><td>全时段</td></tr><tr><td>关注属性</td><td>C / A</td><td>C / A / L</td><td>可用 / 软状态 / 最终一致</td></tr><tr><td>用途</td><td>理解为什么不能既要又要</td><td>真实系统延迟取舍</td><td>工程实战落地</td></tr><tr><td>局限</td><td>不管延迟</td><td>不管业务降级</td><td>不管业务正确性如何兜底</td></tr></tbody></table><hr><h2 id="九、面试-白板高频问题" tabindex="-1">九、面试 / 白板高频问题 <a class="header-anchor" href="#九、面试-白板高频问题" aria-label="Permalink to &quot;九、面试 / 白板高频问题&quot;">​</a></h2><h3 id="_9-1-为什么-zk-是-cp-eureka-是-ap" tabindex="-1">9.1 &quot;为什么 ZK 是 CP,Eureka 是 AP&quot; <a class="header-anchor" href="#_9-1-为什么-zk-是-cp-eureka-是-ap" aria-label="Permalink to &quot;9.1 &quot;为什么 ZK 是 CP,Eureka 是 AP&quot;&quot;">​</a></h3><ul><li><strong>ZK</strong>:写要 majority Quorum,<strong>分区时少数派不可写</strong>——配置中心场景宁可拒写也不要错配</li><li><strong>Eureka</strong>:任意节点都能写,分区时各自接受注册——<strong>服务发现场景宁可路由到旧实例也不要服务列表为空</strong></li></ul><blockquote><p><strong>同一个&quot;注册中心&quot; 类别下,选 CP 还是 AP 完全取决于业务</strong>——配置不能错 → CP;服务发现宁可旧 → AP。</p></blockquote><h3 id="_9-2-为什么金融业还在用-2pc-而不是-saga" tabindex="-1">9.2 &quot;为什么金融业还在用 2PC,而不是 Saga&quot; <a class="header-anchor" href="#_9-2-为什么金融业还在用-2pc-而不是-saga" aria-label="Permalink to &quot;9.2 &quot;为什么金融业还在用 2PC,而不是 Saga&quot;&quot;">​</a></h3><ul><li><strong>2PC</strong>:CP,慢但强一致。<strong>协调者挂会卡死,但金融业宁可卡死也不要钱算错</strong></li><li><strong>Saga</strong>:AP / 最终一致,快但每一步都要写&quot;补偿逻辑&quot;</li></ul><p>金融核心账户 → 2PC;支付的周边业务(通知、记录、营销)→ Saga / 最终一致。<strong>别一刀切</strong>。</p><h3 id="_9-3-spanner-是-cp-怎么做到-5-个-9-可用性" tabindex="-1">9.3 &quot;Spanner 是 CP,怎么做到 5 个 9 可用性&quot; <a class="header-anchor" href="#_9-3-spanner-是-cp-怎么做到-5-个-9-可用性" aria-label="Permalink to &quot;9.3 &quot;Spanner 是 CP,怎么做到 5 个 9 可用性&quot;&quot;">​</a></h3><ul><li>多副本(5 副本 Paxos 默认)</li><li>多机房(同地域 3 zone)</li><li>多区域(跨地域)</li><li>TrueTime 把&quot;等待&quot;控制在 7ms 内</li><li>客户端重试 + 快速选主</li></ul><p><strong>CP ≠ 低可用</strong>。<strong>工程做得足够好,CP 系统的可用性比 AP 的&quot;假可用&quot;高得多</strong>。</p><h3 id="_9-4-我们用最终一致-延迟无所谓吧" tabindex="-1">9.4 &quot;我们用最终一致,延迟无所谓吧&quot; <a class="header-anchor" href="#_9-4-我们用最终一致-延迟无所谓吧" aria-label="Permalink to &quot;9.4 &quot;我们用最终一致,延迟无所谓吧&quot;&quot;">​</a></h3><p><strong>错</strong>。最终一致<strong>也有 SLA</strong>——通常承诺 P99 收敛时间(如 99% 数据 1s 内一致)。</p><ul><li>主从延迟超阈值要告警</li><li>读自己写的链路不能走最终一致</li><li>必须有对账兜底</li></ul><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>把 CAP 当世界观</strong>——它只是一个特定模型下的不可能结果,不是&quot;分布式系统的全部&quot;</li><li><strong>画 CA / CP / AP 三角形</strong>——P 不在你的选项里,<strong>只有 CP 和 AP 的连续谱</strong></li><li><strong>整系统打 CP / AP 标签</strong>——CAP 是&quot;按操作 / 按数据&quot;细分的,<strong>不是公司战略</strong></li><li><strong>以为 ACID = CP、BASE = AP</strong>——这是两个 axis,不能简单等号</li><li><strong>以为 NoSQL = AP</strong>——MongoDB / HBase 默认 CP,Cassandra 可调 CP</li><li><strong>以为强一致就一定慢得不能用</strong>——同机房 Raft 写 1-3ms,跨地域 50ms,<strong>慢不慢看你能否接受</strong></li><li><strong>忽略 PACELC 的 ELC 部分</strong>——平时的延迟代价比分区时的可用代价<strong>发生得更频繁</strong></li><li><strong>BASE 不配对账机制</strong>——异步复制可能丢消息,<strong>没有对账兜底的 eventual consistency 是定时炸弹</strong></li><li><strong>以为&quot;我们没分区&quot;</strong>——生产环境每月都有,<strong>灰分区比硬分区更常见也更难处理</strong></li><li><strong>把 CAP 决策只交给技术</strong>——CAP 是产品 + 业务决策,<strong>技术不知道业务真正在乎什么,拍出来的决策几乎都错</strong></li></ol><hr><p><strong>这一篇收束</strong>:CAP 不是用来背的,是用来&quot;指向&quot;的——指向&quot;分区时你要在 C 和 A 之间选&quot;这件事,然后用 PACELC 把&quot;平时延迟&quot; 也指出来,最后用 BASE 把工程落地的姿势讲清楚。<strong>面试时背&quot;三选二&quot;会扣分,真懂的人讲&quot;按操作精细化选择 + 用 PACELC 看正常态 + 用 BASE 落地工程&quot;</strong>。</p><p>下一篇:<code>05-物理时钟为什么不靠谱.md</code>,从&quot;为什么分布式系统下你不能信本地时钟&quot;讲起——晶振漂移、NTP、闰秒、Cassandra 因为时钟错乱丢数据、Cloudflare 因为闰秒挂了全球 DNS——以及为什么&quot;用本地时间戳排序&quot;是分布式系统的第一大原罪。</p>`,123)])])}const h=a(e,[["render",l]]);export{g as __pageData,h as default};
